#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=50005,mod=10007;
int n,m,mx,a[N],s[N],dp[N],sumdp[N],nxt[N];//nxt i 为是s[i]-s[nxt[i]]<=ans 的第一个数 (ans是第一问的答案)
bool check(int mid)
{
	int cnt=0,sum=0;
	for(int i=1;i<=n;i++)
	{
		sum+=a[i];
		if(sum>mid)
		{
			cnt++;
			sum=a[i];
		}
	}
	return cnt<=m;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		s[i]=s[i-1]+a[i];
		mx=max(mx,a[i]);
	}
	int l=mx,r=s[n],mid;
	while(l<=r)
	{
		mid=(l+r)/2;
		if(check(mid)) r=mid-1;
		else l=mid+1;
	}
	int tmp=r+1;
	cout<<tmp<<" ";
	l=0;
	for(r=1;r<=n;r++)
	{
		for(;;l++)
		{
			if(s[r]-s[l]<=tmp)
			{
				nxt[r]=l;
				break;
			}
		}
	}
	int ans=0;
	for(int i=1;i<=n;i++)
	{
		dp[i]=(s[i]<=tmp);
		sumdp[i]=(sumdp[i-1]+dp[i])%mod;
	}
	for(int i=2;i<=m+1;i++)
	{
		for(int j=1;j<=n;j++)
		{
			dp[j]=sumdp[j-1];
			if(nxt[j]>=1)
			{
				dp[j]=(dp[j]-sumdp[nxt[j]-1]+mod)%mod;
			}
		}
		for(int j=1;j<=n;j++) sumdp[j]=(sumdp[j-1]+dp[j])%mod;
		ans=(ans+dp[n])%mod;
	}
	cout<<ans+(s[n]<=tmp);
	return 0;
}
